import org.springframework.web.bind.annotation.*;
import java.util.regex.Pattern;

@RestController
public class CodeEvaluationControllerSecure {

  @GetMapping("/api/max")
  public String maxSecure(@RequestParam("value") String userInput) {
    // Secure evaluation: strict input validation
    Integer parsedValue = trySanitizeInteger(userInput);
    if (parsedValue == null) {
      return "Invalid input: expected a 32-bit integer.";
    }
    int result = Math.max(10, parsedValue); // ✓ OK
    return "Result: " + result;
  }

  // Strict validation: numeric whitelist and safe parsing
  private Integer trySanitizeInteger(String input) {
    if (input == null || input.trim().isEmpty()) return null;
    input = input.trim();
    // Whitelist: only optional +/-, then digits
    if (!Pattern.matches("^[+-]?\\d+$", input)) return null;
    try {
      return Integer.parseInt(input);
    } catch (NumberFormatException e) {
      return null;
    }
  }
}


