using System;
using System.Text.RegularExpressions;
using System.Collections.Generic;
using Confluent.Kafka;

internal class Program
{
  private static readonly Dictionary<string, string> config = new()
  {
    { "bootstrap.servers", "localhost:9092" },
    { "group.id", "qr8500-eval-consumer" },
    { "auto.offset.reset", "earliest" }
  };

  // Secure: input is validated and parsed by a dedicated sanitizer before being used.
  // This prevents code injection by treating the Kafka payload as data (an integer) rather than executable code.
  private static int Evaluation_secure()
  {
    using var consumer = new ConsumerBuilder<Ignore, string>(config).Build();
    consumer.Subscribe("evaluation-requests");
    var result = consumer.Consume(TimeSpan.FromSeconds(10));

    if (result is null)
      return 0;

    string userInput = result.Message.Value ?? string.Empty;

    // Secure evaluation that delegates sanitization to a single-purpose method
    if (!TrySanitizeInteger(userInput, out var parsedValue))
    {
      Console.WriteLine("Invalid input: expected a 32-bit integer.");
      return 0;
    }

    var resultValue = Math.Max(10, parsedValue); // ✓ OK
    Console.WriteLine($"Result: {resultValue}");
    return resultValue;
  }

  // Method dedicated to securing user input: strict whitelist + safe parse
  private static bool TrySanitizeInteger(string input, out int value)
  {
    value = 0;

    if (string.IsNullOrWhiteSpace(input))
      return false;

    input = input.Trim();

    // Whitelist: only optional leading +/-, then digits
    if (!Regex.IsMatch(input, @"^[+-]?\d+$"))
      return false;

    // Safe numeric parse (protects against overflow and non-numeric content)
    return int.TryParse(input, out value);
  }
}

